  def format_object(predicate: str, obj) -> str:
          """
          Normalise the object value:
          * Convert non‑string values to string.
          * Remove surrounding quotes.
          * Append appropriate units for length/elevation predicates.
          """
          # Ensure we are working with a string
          obj = str(obj)
          # Strip surrounding quotes if present
          if obj.startswith('"') and obj.endswith('"'):
              obj = obj[1:-1]

          lower = predicate.lower()
          # Length / elevation handling
          if "feet" in lower:
              if not obj.lower().endswith("feet"):
                  obj = f"{obj} feet"
          elif "metre" in lower or "metres" in lower:
              if not obj.lower().endswith("metres"):
                  obj = f"{obj} metres"
          elif predicate in {"runwayLength", "elevationAboveTheSeaLevel"}:
              # These predicates are typically expressed in metres
              if not (obj.lower().endswith("metres") or obj.lower().endswith("m")):
                  obj = f"{obj} metres"
          return obj
